import { x402Client, wrapFetchWithPayment } from "@x402/fetch";
import { ExactEvmScheme } from "@x402/evm/exact/client";
import { privateKeyToAccount } from "viem/accounts";

const BASE_URL = "https://stockwaves.net";
const signer = privateKeyToAccount(process.env.EVM_PRIVATE_KEY as `0x${string}`);

// No API key, no signup — every endpoint is x402 pay-per-call (USDC on Base or Solana).
const client = new x402Client();
client.register("eip155:*", new ExactEvmScheme(signer));
const pay = wrapFetchWithPayment(fetch, client);

// China social pulse — Weibo + Baidu + Douyin hot-search, structured (~$0.03)
const pulse = await (await pay(`${BASE_URL}/api/cn/trending?platform=all&limit=20`)).json();

// Pre-trade safety on a tokenized US stock: is this the REAL issuer token vs a copycat? (~$0.03)
const gate = await (await pay(`${BASE_URL}/api/xstock/health?symbol=AAPLx`)).json();

// FREE — no payment: proof-before-you-buy backtest, and a free safety preview
const track = await (await fetch(`${BASE_URL}/api/track-record`)).json();
const preview = await (await fetch(`${BASE_URL}/api/xstock/health/preview?symbol=NVDAx`)).json();
